app = Flask(__name__)
_AUTH_USER = os.environ.get("DASHBOARD_USER", "")
_AUTH_PASS = os.environ.get("DASHBOARD_PASS", "")
def check_auth(u, p):
    au = _AUTH_USER or get_config().get("dashboard", {}).get("user", "admin")
    ap = _AUTH_PASS or get_config().get("dashboard", {}).get("password", "admin123")
    return u == au and p == ap
def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.authorization
        if not auth or not check_auth(auth.username, auth.password):
            return Response("Login required", 401, {"WWW-Authenticate": 'Basic realm="Dashboard"'})
        return f(*args, **kwargs)
    return decorated
log = logging.getLogger("dashboard")

DB_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "trades.db")

def init_db():
    """Create balance_snapshots table if not exists"""
    try:
        conn = sqlite3.connect(DB_PATH)
        conn.execute("""CREATE TABLE IF NOT EXISTS balance_snapshots (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            timestamp TEXT DEFAULT (datetime('now')),
            eur_balance REAL DEFAULT 0,
            btc_balance REAL DEFAULT 0,
            btc_eur_value REAL DEFAULT 0,
            total_eur REAL DEFAULT 0,
            spot_price REAL DEFAULT 0,
            source TEXT DEFAULT 'auto'
        )""")
        conn.execute("""CREATE TABLE IF NOT EXISTS balance_flows (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            timestamp TEXT DEFAULT (datetime('now')),
            type TEXT,
            direction TEXT,
            amount REAL DEFAULT 0,
            currency TEXT,
            description TEXT,
            balance_after REAL DEFAULT 0
        )""")
        conn.execute("""CREATE TABLE IF NOT EXISTS premium_history (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            timestamp TEXT DEFAULT (datetime('now')),
            currency TEXT,
            num_offers INTEGER DEFAULT 0,
            lowest REAL DEFAULT 0,
            median REAL DEFAULT 0,
            avg REAL DEFAULT 0,
            highest REAL DEFAULT 0
        )""")
        conn.execute("""CREATE TABLE IF NOT EXISTS trades (
            id INTEGER PRIMARY KEY AUTOINCREMENT, timestamp TEXT NOT NULL,
            platform TEXT NOT NULL, exchange TEXT NOT NULL, contract_id TEXT,
            amount_sats INTEGER, buy_price REAL, sell_price REAL,
            currency TEXT DEFAULT 'EUR', premium_pct REAL,
            exchange_fee REAL DEFAULT 0, platform_fee REAL DEFAULT 0,
            network_fee REAL DEFAULT 0, net_profit REAL DEFAULT 0,
            payment_method TEXT, status TEXT DEFAULT 'completed',
            withdrawal_fee REAL DEFAULT 0, funding_fee REAL DEFAULT 0,
            spot_at_buy REAL DEFAULT 0, spot_at_sell REAL DEFAULT 0)""")
        for col, default in [("withdrawal_fee", 0), ("funding_fee", 0),
                             ("spot_at_buy", 0), ("spot_at_sell", 0)]:
            try:
                conn.execute(f"ALTER TABLE trades ADD COLUMN {col} REAL DEFAULT {default}")
            except Exception:
                pass
        conn.execute("""CREATE TABLE IF NOT EXISTS events (
            id INTEGER PRIMARY KEY AUTOINCREMENT, timestamp TEXT NOT NULL,
            platform TEXT, event_type TEXT NOT NULL, data TEXT)""")
        conn.commit()
        conn.close()
    except Exception as e:
        log.error(f"DB init error: {e}")

init_db()

def snapshot_balance():
    """Take a balance snapshot from Kraken"""
    try:
        ex = safe_exchange()
        eur = float(ex.get("eur", 0) or 0)
        btc = float(ex.get("btc", 0) or 0)
        spot = float(ex.get("spot", 0) or 0)
        btc_eur = btc * spot
        total = eur + btc_eur

        db = get_db()
        if not db: return

        # Check last snapshot - only save if >5 min old
        last = db.execute("SELECT timestamp FROM balance_snapshots ORDER BY id DESC LIMIT 1").fetchone()
        if last:
            last_time = datetime.fromisoformat(last["timestamp"])
            now = datetime.utcnow()
            if (now - last_time).total_seconds() < 300:
                db.close()
                return

        db.execute("INSERT INTO balance_snapshots (eur_balance, btc_balance, btc_eur_value, total_eur, spot_price) VALUES (?,?,?,?,?)",
            (eur, btc, btc_eur, total, spot))
        db.commit()
        db.close()
    except Exception as e:
        log.error(f"Snapshot error: {e}")

def get_db():
    try:
        conn = sqlite3.connect(DB_PATH)
        conn.row_factory = sqlite3.Row
        return conn
    except Exception as e:
        log.error(f"DB error: {e}")
        return None

def get_config():
    try:
        cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
        with open(cfg_path) as f:
            return json.load(f)
    except Exception:
        return {}

def safe_exchange():
    try:
        import sys
        sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
        from exchanges.kraken import KrakenExchange
        exchanges = get_config().get('exchanges', {})
        # Find first enabled kraken exchange
        cfg = None
        for name, ecfg in exchanges.items():
            if name.startswith('kraken') and ecfg.get('enabled'):
                cfg = ecfg
                break
        if not cfg:
            cfg = exchanges.get('kraken', {})
        k = KrakenExchange(cfg)
        return {"spot": k.get_spot_price(), "eur": k.get_fiat_balance(),
                "btc": k.get_btc_balance(), "online": True}
    except Exception as e:
        return {"spot": 0, "eur": 0, "btc": 0, "online": False, "error": str(e)}

def safe_platform():
    try:
        import sys
        sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
        from platforms.peach import PeachPlatform
        cfg = get_config().get('platforms', {}).get('peach', {})
        p = PeachPlatform(cfg)
        p.authenticate()
        return p.get_status()
    except Exception as e:
        return {"online": False, "error": str(e)}

