@app.route("/api/status")
@requires_auth
def api_status():
    ex = safe_exchange()
    pl = safe_platform()
    # Get USD spot price
    usd_spot = 0
    try:
        r = requests.get("https://api.kraken.com/0/public/Ticker", params={"pair": "XBTUSD"}, timeout=10)
        usd_spot = float(r.json().get("result", {}).get("XXBTZUSD", {}).get("c", [0])[0])
    except Exception:
        # Fallback: estimate from EUR * 1.04
        if ex.get("spot"): usd_spot = float(ex["spot"]) * 1.04
    eur_spot = float(ex.get("spot", 0) or 0)
    eurusd = usd_spot / eur_spot if eur_spot > 0 else 1.04

    # All fiat balances from all enabled kraken exchanges
    fiat_balances = {}
    try:
        from exchanges.kraken import KrakenExchange
        exchanges_cfg = get_config().get('exchanges', {})
        for name, ecfg in exchanges_cfg.items():
            if name.startswith('kraken') and ecfg.get('enabled'):
                ecfg.setdefault('name', name)
                ki = KrakenExchange(ecfg)
                currency = ki.get_fiat_currency()
                fiat_balances[currency] = round(ki.get_fiat_balance(), 2)
    except Exception:
        pass

    return jsonify({"exchange": ex, "platform": pl,
                    "usd_spot": usd_spot, "eurusd": eurusd,
                    "fiat_balances": fiat_balances,
                    "timestamp": datetime.utcnow().isoformat()})

@app.route("/api/trades")
@requires_auth
def api_trades():
    db = get_db()
    if not db: return jsonify([])
    # Delete duplicates before returning
    db.execute("""DELETE FROM trades WHERE id NOT IN (
        SELECT MIN(id) FROM trades GROUP BY contract_id
    ) AND contract_id != '' AND contract_id IS NOT NULL""")
    db.execute("""DELETE FROM trades WHERE (contract_id = '' OR contract_id IS NULL)
        AND id NOT IN (
            SELECT MIN(id) FROM trades
            WHERE contract_id = '' OR contract_id IS NULL
            GROUP BY platform, amount_sats, date(timestamp)
        )""")
    db.commit()
    rows = db.execute(
        "SELECT * FROM trades ORDER BY timestamp DESC").fetchall()
    db.close()
    return jsonify([dict(r) for r in rows])

