@app.route("/api/trades/deduplicate", methods=["POST"])
@requires_auth
def api_trades_deduplicate():
    db = get_db()
    if not db: return jsonify({"error": "no db"}), 500
    before = db.execute("SELECT COUNT(*) FROM trades").fetchone()[0]
    db.execute("""DELETE FROM trades WHERE id NOT IN (
        SELECT MIN(id) FROM trades GROUP BY contract_id
    ) AND contract_id != '' AND contract_id IS NOT NULL""")
    db.execute("""DELETE FROM trades WHERE (contract_id = '' OR contract_id IS NULL)
        AND id NOT IN (
            SELECT MIN(id) FROM trades
            WHERE contract_id = '' OR contract_id IS NULL
            GROUP BY platform, amount_sats, date(timestamp)
        )""")
    db.commit()
    after = db.execute("SELECT COUNT(*) FROM trades").fetchone()[0]
    db.close()
    return jsonify({"removed": before - after, "remaining": after})

@app.route("/api/profit")
@requires_auth
def api_profit():
    db = get_db()
    if not db: return jsonify({"daily": [], "summary": {}})
    # Daily profit (all time)
    rows = db.execute("SELECT date(timestamp) as day, COUNT(*) as count, SUM(net_profit) as profit, SUM(amount_sats) as volume FROM trades GROUP BY date(timestamp) ORDER BY day").fetchall()
    daily = [dict(r) for r in rows]
    # Totals
    tot = db.execute("SELECT COUNT(*) as count, COALESCE(SUM(net_profit),0) as profit, COALESCE(SUM(amount_sats),0) as volume, COALESCE(AVG(premium_pct),0) as avg_premium, COALESCE(AVG(CASE WHEN sell_price_chf > 0 AND net_profit IS NOT NULL THEN (net_profit / (sell_price_chf - net_profit)) * 100 END),0) as avg_net_premium FROM trades").fetchone()
    # Today
    today = db.execute("SELECT COUNT(*) as count, COALESCE(SUM(net_profit),0) as profit FROM trades WHERE date(timestamp) = date('now')").fetchone()
    # This week
    week = db.execute("SELECT COUNT(*) as count, COALESCE(SUM(net_profit),0) as profit FROM trades WHERE timestamp > datetime('now','-7 days')").fetchone()
    db.close()
    return jsonify({
        "daily": daily,
        "summary": dict(tot),
        "today": dict(today),
        "week": dict(week)
    })

