@app.route("/api/bot/status")
@requires_auth
def api_bot_status():
    """Check trading bot service status"""
    try:
        result = subprocess.run(
            ["systemctl", "is-active", "trading-bot"],
            capture_output=True, text=True, timeout=5
        )
        state = result.stdout.strip()  # active, inactive, failed, activating
        uptime_secs = 0
        if state == "active":
            try:
                up = subprocess.run(
                    ["systemctl", "show", "trading-bot", "--property=ActiveEnterTimestampMonotonic"],
                    capture_output=True, text=True, timeout=5
                )
                mono_us = int(up.stdout.strip().replace("ActiveEnterTimestampMonotonic=", ""))
                # Get current monotonic time
                with open("/proc/uptime") as f:
                    system_uptime = float(f.read().split()[0])
                uptime_secs = int(system_uptime - (mono_us / 1_000_000))
                if uptime_secs < 0: uptime_secs = 0
            except Exception: pass
        return jsonify({"state": state, "uptime_secs": uptime_secs})
    except Exception as e:
        return jsonify({"state": "unknown", "error": str(e)})

