@app.route("/api/config/update", methods=["POST"])
@requires_auth
def api_config_update():
    """Update pricing config in config.json"""
    from flask import request as req
    data = req.get_json()
    if not data: return jsonify({"error": "no data"}), 400

    try:
        cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
        with open(cfg_path) as f:
            cfg = json.load(f)

        peach = cfg.setdefault("platforms", {}).setdefault("peach", {})
        pricing = peach.setdefault("dynamic_pricing", {})

        # Update allowed fields only
        allowed = {
            "floor_pct": (float, 0.0, 20.0),
            "ceiling_pct": (float, 1.0, 30.0),
            "undercut_by": (float, 0.0, 5.0),
        }
        allowed_peach = {
            "target_premium": (float, 0.0, 30.0),
        }

        changes = {}
        for key, (typ, lo, hi) in allowed.items():
            if key in data:
                val = typ(data[key])
                val = max(lo, min(hi, val))
                pricing[key] = val
                changes[key] = val

        for key, (typ, lo, hi) in allowed_peach.items():
            if key in data:
                val = typ(data[key])
                val = max(lo, min(hi, val))
                peach[key] = val
                changes[key] = val

        with open(cfg_path, 'w') as f:
            json.dump(cfg, f, indent=2)

        return jsonify({"ok": True, "changes": changes})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

