@app.route("/api/balances")
@requires_auth
def api_balances():
    """Balance history and flow data"""
    # Take a fresh snapshot
    snapshot_balance()

    db = get_db()
    if not db: return jsonify({"snapshots": [], "flows": [], "current": {}})

    # Last 7 days of snapshots (1 per hour max)
    snaps = db.execute("""
        SELECT timestamp, eur_balance, btc_balance, btc_eur_value, total_eur, spot_price
        FROM balance_snapshots
        WHERE timestamp > datetime('now', '-7 days')
        ORDER BY timestamp
    """).fetchall()

    # Recent flows
    flows = db.execute("""
        SELECT * FROM balance_flows
        ORDER BY timestamp DESC LIMIT 50
    """).fetchall()

    # Current totals
    current = db.execute("""
        SELECT eur_balance, btc_balance, btc_eur_value, total_eur, spot_price
        FROM balance_snapshots ORDER BY id DESC LIMIT 1
    """).fetchone()

    # Calculate inflows/outflows from flows table
    flow_summary = db.execute("""
        SELECT
            direction,
            currency,
            SUM(amount) as total
        FROM balance_flows
        WHERE timestamp > datetime('now', '-30 days')
        GROUP BY direction, currency
    """).fetchall()

    db.close()

    return jsonify({
        "snapshots": [dict(s) for s in snaps],
        "flows": [dict(f) for f in flows],
        "current": dict(current) if current else {},
        "flow_summary": [dict(f) for f in flow_summary]
    })

