@app.route("/api/wallet")
@requires_auth
def api_wallet():
    """Hot Wallet balance, UTXOs and transactions"""
    result = {"address": "", "balance": 0, "utxos": [], "txs": [], "mempool": {}}
    try:
        cfg = get_config()
        address = cfg.get("platforms", {}).get("peach", {}).get("refund_address", "")
        result["address"] = address
        if not address:
            return jsonify(result)

        # Balance + stats
        r = requests.get(f"https://mempool.space/api/address/{address}", timeout=10)
        r.raise_for_status()
        data = r.json()
        chain = data.get("chain_stats", {})
        mempool = data.get("mempool_stats", {})
        funded = chain.get("funded_txo_sum", 0)
        spent = chain.get("spent_txo_sum", 0)
        result["balance"] = funded - spent
        result["mempool"] = {
            "pending_in": mempool.get("funded_txo_sum", 0),
            "pending_out": mempool.get("spent_txo_sum", 0)
        }
        result["tx_count"] = chain.get("tx_count", 0)

        # UTXOs
        try:
            r2 = requests.get(f"https://mempool.space/api/address/{address}/utxo", timeout=10)
            r2.raise_for_status()
            utxos = r2.json()
            result["utxos"] = [{
                "txid": u.get("txid", "")[:16] + "...",
                "txid_full": u.get("txid", ""),
                "vout": u.get("vout", 0),
                "value": u.get("value", 0),
                "confirmed": u.get("status", {}).get("confirmed", False)
            } for u in utxos]
        except Exception:
            pass

        # Recent transactions
        try:
            r3 = requests.get(f"https://mempool.space/api/address/{address}/txs", timeout=10)
            r3.raise_for_status()
            txs = r3.json()[:20]
            parsed = []
            for tx in txs:
                # Determine if incoming or outgoing
                total_in = sum(v.get("prevout", {}).get("value", 0) for v in tx.get("vin", [])
                              if v.get("prevout", {}).get("scriptpubkey_address", "") == address)
                total_out = sum(v.get("value", 0) for v in tx.get("vout", [])
                              if v.get("scriptpubkey_address", "") == address)
                net = total_out - total_in
                confirmed = tx.get("status", {}).get("confirmed", False)
                block_time = tx.get("status", {}).get("block_time", 0)
                parsed.append({
                    "txid": tx.get("txid", "")[:16] + "...",
                    "txid_full": tx.get("txid", ""),
                    "net": net,
                    "fee": tx.get("fee", 0),
                    "confirmed": confirmed,
                    "time": block_time,
                    "size": tx.get("size", 0)
                })
            result["txs"] = parsed
        except Exception:
            pass

        # Spot price for USD value
        try:
            sr = requests.get("https://api.kraken.com/0/public/Ticker", params={"pair": "XBTUSD"}, timeout=5)
            spot = float(sr.json().get("result", {}).get("XXBTZUSD", {}).get("c", [0])[0])
            result["spot_usd"] = spot
            result["balance_usd"] = round(result["balance"] / 1e8 * spot, 2)
        except Exception:
            pass

    except Exception as e:
        result["error"] = str(e)
    return jsonify(result)

@app.route("/api/kraken")
@requires_auth
def api_kraken():
    """Kraken ledger, trades and balance snapshots"""
    result = {"trades": [], "balances": [], "flows": {}, "currencies": {}}
    try:
        import sys, time as _time
        sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
        from exchanges.kraken import KrakenExchange
        exchanges_cfg = get_config().get('exchanges', {})

        # Find all enabled kraken exchanges
        kraken_instances = {}
        for name, ecfg in exchanges_cfg.items():
            if name.startswith('kraken') and ecfg.get('enabled'):
                ecfg.setdefault('name', name)
                kraken_instances[name] = KrakenExchange(ecfg)

        # Fallback: old config style with single 'kraken' key
        if not kraken_instances and exchanges_cfg.get('kraken'):
            kraken_instances['kraken'] = KrakenExchange(exchanges_cfg['kraken'])

        # Use first instance for trades (same Kraken account)
        k = list(kraken_instances.values())[0] if kraken_instances else None
        if not k:
            result["error"] = "No Kraken exchange configured"
            return jsonify(result)

        # Flows from TradesHistory (Ledger API has no permission)
        try:
            all_trades = k.get_trade_history(days=30)
            result["trades"] = all_trades[:30]
            chf_spent = sum(float(t.get("cost", 0)) for t in all_trades if "CHF" in t.get("pair", ""))
            btc_bought = sum(float(t.get("vol", 0)) for t in all_trades if t.get("type") == "buy")
            btc_sold = sum(float(t.get("vol", 0)) for t in all_trades if t.get("type") == "sell")
            fees_chf = sum(float(t.get("fee", 0)) for t in all_trades if "CHF" in t.get("pair", ""))
            eur_spent = sum(float(t.get("cost", 0)) for t in all_trades if "EUR" in t.get("pair", ""))
            fees_eur = sum(float(t.get("fee", 0)) for t in all_trades if "EUR" in t.get("pair", ""))
            result["flows"] = {
                "chf_spent": round(chf_spent, 2),
                "eur_spent": round(eur_spent, 2),
                "btc_bought": round(btc_bought, 8),
                "btc_sold": round(btc_sold, 8),
                "net_btc": round(btc_bought - btc_sold, 8),
                "fees_chf": round(fees_chf, 2),
                "fees_eur": round(fees_eur, 2),
                "total_trades": len(all_trades)
            }
        except Exception as e:
            result["flows_error"] = str(e)

        # Per-currency balances and spot prices
        for name, ki in kraken_instances.items():
            currency = ki.get_fiat_currency()
            try:
                fiat = ki.get_fiat_balance()
                btc = ki.get_btc_balance()
                spot = ki.get_spot_price()
                result["currencies"][currency] = {
                    "fiat": round(fiat, 2),
                    "btc": round(btc, 8),
                    "spot": round(spot, 0),
                    "btc_in_fiat": round(btc * spot, 2),
                    "total": round(fiat + btc * spot, 2)
                }
            except Exception as e:
                result["currencies"][currency] = {"error": str(e)}

        # Save balance snapshot (use CHF if available, else first)
        try:
            primary = kraken_instances.get('kraken_chf') or k
            eur = primary.get_fiat_balance()
            btc = primary.get_btc_balance()
            spot = primary.get_spot_price()
            total = eur + (btc * spot)
            result["current"] = {
                "chf": round(eur, 2),
                "btc": round(btc, 8),
                "spot_chf": round(spot, 0),
                "btc_in_chf": round(btc * spot, 2),
                "total_chf": round(total, 2)
            }
            db = get_db()
            if db:
                db.execute("INSERT INTO balance_snapshots (eur_balance, btc_balance, btc_eur_value, total_eur, spot_price) VALUES (?,?,?,?,?)",
                    (eur, btc, btc * spot, total, spot))
                db.commit()
                rows = db.execute("SELECT * FROM balance_snapshots ORDER BY timestamp DESC LIMIT 100").fetchall()
                result["balances"] = [dict(r) for r in rows]
                db.close()
        except Exception as e:
            result["balance_error"] = str(e)

    except Exception as e:
        result["error"] = str(e)
    return jsonify(result)

@app.route("/api/market")
@requires_auth
def api_market():
    """Scan competitor premiums on P2P platforms"""
    result = {"peach": {}, "timestamp": datetime.utcnow().isoformat()}

    # Get USD spot for all platforms
    spot_usd = 0
    try:
        sr = requests.get("https://api.kraken.com/0/public/Ticker", params={"pair": "XBTUSD"}, timeout=10)
        spot_usd = float(sr.json().get("result", {}).get("XXBTZUSD", {}).get("c", [0])[0])
    except Exception: pass
    result["spot_usd"] = spot_usd

    # Peach - scan EUR with different payment methods
    try:
        all_premiums = []
        all_detailed = []
        seen = set()
        searches = [
            ("EUR", "sepa"),
            ("EUR", "instantSepa"),
            ("EUR", "revolut"),
            ("EUR", "wise"),
            ("CHF", "sepa"),
            ("CHF", "revolut"),
            ("CHF", "wise"),
            ("CHF", "twint"),
            ("USD", "revolut"),
            ("USD", "wise"),
        ]
        for curr, method in searches:
            try:
                r = requests.post("https://api.peachbitcoin.com/v1/offer/search",
                    json={"type": "ask", "meansOfPayment": {curr: [method]}}, timeout=15)
                r.raise_for_status()
                offers = r.json()
                raw = offers if isinstance(offers, list) else offers.get("offers", [])
                for o in raw:
                    p = o.get("premium")
                    if p is not None and isinstance(p, (int, float)) and float(p) >= 2.0:
                        oid = f"{o.get('id', '')}_{curr}"
                        if oid in seen: continue
                        seen.add(oid)
                        all_premiums.append(float(p))
                        pay_methods = []
                        mop = o.get("meansOfPayment", {})
                        for c, ms in mop.items():
                            for m in ms:
                                pay_methods.append(m)
                        all_detailed.append({
                            "amount_sats": o.get("amount", 0),
                            "premium": float(p),
                            "price_eur": o.get("prices", {}).get("EUR", o.get("prices", {}).get(curr, 0)),
                            "currency": curr,
                            "payment": ", ".join(pay_methods) if pay_methods else method,
                            "online": o.get("online", False),
                            "date": o.get("publishingDate", "")[:16].replace("T", " ")
                        })
            except Exception: continue
        all_premiums = sorted(all_premiums)
        all_detailed = sorted(all_detailed, key=lambda x: x["premium"])
        result["peach"] = {
            "online": True,
            "num_offers": len(all_detailed),
            "premiums": all_premiums[:40],
            "offers": all_detailed[:60],
            "lowest": round(min(all_premiums), 1) if all_premiums else 0,
            "median": round(sorted(all_premiums)[len(all_premiums)//2], 1) if all_premiums else 0,
            "highest": round(max(all_premiums), 1) if all_premiums else 0,
            "avg": round(sum(all_premiums)/len(all_premiums), 1) if all_premiums else 0
        }
    except Exception as e:
        result["peach"] = {"online": False, "error": str(e), "num_offers": 0, "premiums": []}

    # Save premium history per currency
    try:
        db = get_db()
        if db and result.get("peach", {}).get("online"):
            offers = result["peach"].get("offers", [])
            for curr in ["EUR", "CHF", "USD"]:
                curr_offers = [o for o in offers if o.get("currency") == curr]
                prems = sorted([o["premium"] for o in curr_offers])
                if prems:
                    # Only save if last entry is >15 min old
                    last = db.execute(
                        "SELECT timestamp FROM premium_history WHERE currency=? ORDER BY id DESC LIMIT 1",
                        (curr,)).fetchone()
                    save = True
                    if last:
                        last_t = datetime.fromisoformat(last["timestamp"])
                        if (datetime.utcnow() - last_t).total_seconds() < 900:
                            save = False
                    if save:
                        db.execute(
                            "INSERT INTO premium_history (currency,num_offers,lowest,median,avg,highest) VALUES (?,?,?,?,?,?)",
                            (curr, len(prems), round(min(prems),1),
                             round(prems[len(prems)//2],1),
                             round(sum(prems)/len(prems),1),
                             round(max(prems),1)))
            db.commit()
            db.close()
    except Exception as e:
        log.error(f"Premium history save error: {e}")

    return jsonify(result)

